pseudocode:
1. import { Client } from '@notionhq/client', { z } from 'zod', { getEnv } from '@/lib/env', { logger } from '@/lib/logger'
2. export interface Project/Career/Skill, GetProjectsOptions/GetCareersOptions/GetSkillsOptions 정의 (PRD '데이터 플로우 및 타입 정의' 섹션 그대로)
3. const ProjectSchema/CareerSchema/SkillSchema = z.object({...}) (PRD 동일 섹션 그대로)
4. let cachedClient: Client | null = null; function getClient(): Client { if (!cachedClient) { const env = getEnv(); cachedClient = new Client({ auth: env.NOTION_API_KEY }) } return cachedClient }
5. function parseProjectPage(page): Project { properties 접근 패턴(title[0]?.plain_text, rich_text.map(...).join(''), multi_select.map(s=>s.name), files[0]?.file?.url ?? null, url, checkbox, select.name, number, new Date(page.created_time)) }
6. function parseCareerPage(page): Career { company=title, role=rich_text 또는 text, startDate=date.start, endDate=date.end ?? null, description=rich_text, order=number }
7. function parseSkillPage(page): Skill { name=title, category=select.name, proficiency=number, order=number }
8. function buildProjectFilter(options), buildProjectSorts(options) 등 헬퍼로 filter/sorts 객체 구성, 복수 조건은 { and: [...] }
9. export async function getProjects(options?) { try { logger.info(...); const client=getClient(); const res = await client.databases.query({ database_id: getEnv().NOTION_PROJECTS_DB_ID, filter: buildProjectFilter(options), sorts: buildProjectSorts(options) }); const projects = res.results.map(parseProjectPage).map(p=>ProjectSchema.parse(p)); logger.info(count); return projects } catch(e) { logger.error(...); return [] } }
10. export async function getProjectBySlug(slug) { try { ... filter: { property: 'Slug', rich_text: { equals: slug } } ...; if (res.results.length === 0) return null; return ProjectSchema.parse(parseProjectPage(res.results[0])) } catch(e) { logger.error(...); return null } }
11. export async function getProjectNeighbors(slug): Promise<{ prev: Project | null, next: Project | null }> { try { const all = await getProjects({ orderBy: 'Order' }); const idx = all.findIndex(p => p.slug === slug); if (idx === -1) return { prev: null, next: null }; return { prev: idx > 0 ? all[idx-1] : null, next: idx < all.length-1 ? all[idx+1] : null } } catch(e) { logger.error(...); return { prev: null, next: null } } } — 이 함수가 prev/next 계산 로직 전체를 캡슐화하여 app/projects/[slug]/page.tsx는 이 함수 호출 결과만 props로 전달.
12. export async function getCareers(options?), getSkills(options?) 동일 패턴
13. export async function getProjectCount(options?) { const projects = await getProjects(options); return projects.length }

