1. app/projects/page.tsx: export const revalidate=3600; export const metadata={title:'Projects'}; async function ProjectsPage(){ try{ const projects = await getProjects({status:'Active', orderBy:'Order'}); return <main><h1>프로젝트</h1><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">{projects.map(p=><ProjectCard key={p.id} project={p}/>)}</div></main> }catch(e){logger.error(...); return <div>프로젝트를 불러올 수 없습니다.</div>} }
2. app/projects/[slug]/page.tsx: export const revalidate=3600; export async function generateStaticParams(){ const projects=await getProjects(); return projects.map(p=>({slug:p.slug})) } export async function generateMetadata({params}:{params:Promise<{slug:string}>}){ const {slug}=await params; const project=await getProjectBySlug(slug); if(!project) return {}; return {title:project.name, description:project.description} } export default async function ProjectDetailPage({params}:{params:Promise<{slug:string}>}){ const {slug}=await params; try{ const project = await getProjectBySlug(slug); if(!project) notFound(); const { prev, next } = await getProjectNeighbors(slug); return <main><ProjectDetail project={project}/><ProjectNavigation prev={prev} next={next}/><Link href="/projects">← 모든 프로젝트로</Link></main> }catch(e){ logger.error(...); notFound() } } — 페이지는 getProjectNeighbors 호출 결과를 그대로 props로 전달할 뿐, 인덱스 계산이나 정렬 로직을 직접 수행하지 않음.

