export const revalidate=3600;
async function HomePage(){
  try {
    const [featuredProjects, topSkills] = await Promise.all([
      getProjects({featured:true, limit:5}),
      getSkills({minProficiency:8})
    ]);
    return (
      <>
        {/* 기존 Hero 블록 그대로 유지 */}
        <section>{featuredProjects.map(p=><ProjectCard key={p.id} project={p}/>)}</section>
        <section><SkillsGrid skills={topSkills}/></section>
      </>
    )
  } catch(e) { logger.error(...); /* 기존 Hero는 보여주고 섹션만 fallback, 또는 전체 fallback */ }
}
